query:
-- 统计老师总数
SELECT COUNT(*) as total FROM teachers;

-- 按城市统计老师分布
SELECT city, COUNT(*) as count FROM teachers GROUP BY city ORDER BY count DESC;

-- 按老师属性统计
SELECT teacherAttribute, COUNT(*) as count FROM teachers GROUP BY teacherAttribute;

